import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicCenter() {
        int[][] image = {
            {1, 1, 1},
            {1, 1, 0},
            {1, 0, 1}
        };
        new Solution().floodFill(image, 1, 1, 2);
        assertArrayEquals(new int[][]{
            {2, 2, 2},
            {2, 2, 0},
            {2, 0, 1}
        }, image);
    }

    @Test
    void alreadyNewColor_noChange() {
        // Guard: starting cell already has newColor — image must not change
        int[][] image = {{0, 0, 0}, {0, 1, 1}};
        int[][] expected = {{0, 0, 0}, {0, 1, 1}};
        new Solution().floodFill(image, 1, 1, 1);
        assertArrayEquals(expected, image);
    }

    @Test
    void singleCellGrid() {
        int[][] image = {{5}};
        new Solution().floodFill(image, 0, 0, 9);
        assertArrayEquals(new int[][]{{9}}, image);
    }

    @Test
    void fillDoesNotCrossOtherColor() {
        int[][] image = {
            {1, 1, 0},
            {1, 0, 0},
            {0, 0, 1}
        };
        new Solution().floodFill(image, 0, 0, 3);
        assertArrayEquals(new int[][]{
            {3, 3, 0},
            {3, 0, 0},
            {0, 0, 1}
        }, image);
    }

    @Test
    void emptyMatrix() {
        int[][] image = {};
        new Solution().floodFill(image, 0, 0, 1); // must not throw
        assertEquals(0, image.length);
    }

    @Test
    void entireGridSameColor() {
        int[][] image = {
            {2, 2},
            {2, 2}
        };
        new Solution().floodFill(image, 0, 0, 7);
        assertArrayEquals(new int[][]{{7,7},{7,7}}, image);
    }

    @Test
    void nonSquareRectangle() {
        // 2×4 grid — verify non-square traversal
        int[][] image = {
            {0, 0, 0, 0},
            {0, 1, 0, 0}
        };
        new Solution().floodFill(image, 0, 0, 5);
        assertArrayEquals(new int[][]{
            {5, 5, 5, 5},
            {5, 1, 5, 5}
        }, image);
    }
}
